import{_ as t,o as s,c as a,ai as d}from"./chunks/framework.LYGRWSbL.js";const p=JSON.parse('{"title":"Expressions de temps","description":"","frontmatter":{"next":{"text":"Module 5 - Aller plus loin","link":"../module-5-aller-plus-loin/"}},"headers":[],"relativePath":"module-4-le-temps/expressions-de-temps.md","filePath":"module-4-le-temps/expressions-de-temps.md","lastUpdated":1773298982000}'),i={name:"module-4-le-temps/expressions-de-temps.md"};function r(n,e,l,o,c,m){return s(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="expressions-de-temps" tabindex="-1">Expressions de temps <a class="header-anchor" href="#expressions-de-temps" aria-label="Permalink to “Expressions de temps”">​</a></h1><p><strong>Prérequis :</strong> <a href="./futur.html">Le futur</a></p><p><strong>Objectif :</strong> disposer du vocabulaire temporel essentiel pour situer une action dans le temps.</p><p>Ces expressions sont indispensables dès les premiers échanges. Elles s&#39;utilisent avec le présent, le Perfekt et le futur.</p><h2 id="hier-aujourd-hui-demain" tabindex="-1">Hier, aujourd&#39;hui, demain <a class="header-anchor" href="#hier-aujourd-hui-demain" aria-label="Permalink to “Hier, aujourd&#39;hui, demain”">​</a></h2><div class="mt-4 grid grid-cols-3 gap-3"><div class="p-3 rounded-xl border border-orange-200 bg-orange-50 text-center"><div class="font-bold text-orange-800 text-lg">gestern</div><div class="text-sm text-gray-600">hier</div><div class="text-xs text-gray-500 italic mt-1">Ich habe gestern geschlafen.</div></div><div class="p-3 rounded-xl border border-green-200 bg-green-50 text-center"><div class="font-bold text-green-800 text-lg">heute</div><div class="text-sm text-gray-600">aujourd&#39;hui</div><div class="text-xs text-gray-500 italic mt-1">Heute ist es kalt.</div></div><div class="p-3 rounded-xl border border-blue-200 bg-blue-50 text-center"><div class="font-bold text-blue-800 text-lg">morgen</div><div class="text-sm text-gray-600">demain</div><div class="text-xs text-gray-500 italic mt-1">Morgen fahre ich weg.</div></div></div><div class="warning custom-block"><p class="custom-block-title">morgen = demain, pas matin</p><p>Le matin se dit <em>der Morgen</em> (nom, avec majuscule) ou <em>morgens</em> (adverbe = le matin en général). <em>Morgen</em> sans majuscule = demain. <em>Heute Morgen</em> = ce matin.</p></div><h2 id="parties-de-la-journee" tabindex="-1">Parties de la journee <a class="header-anchor" href="#parties-de-la-journee" aria-label="Permalink to “Parties de la journee”">​</a></h2><table tabindex="0"><thead><tr><th>Allemand</th><th>Sens</th><th>Avec heute</th></tr></thead><tbody><tr><td>der Morgen</td><td>le matin</td><td><em>heute Morgen</em> - ce matin</td></tr><tr><td>der Vormittag</td><td>la matinee (avant midi)</td><td><em>heute Vormittag</em> - ce matin (avant-midi)</td></tr><tr><td>der Mittag</td><td>midi</td><td><em>heute Mittag</em> - ce midi</td></tr><tr><td>der Nachmittag</td><td>l&#39;après-midi</td><td><em>heute Nachmittag</em> - cet après-midi</td></tr><tr><td>der Abend</td><td>le soir</td><td><em>heute Abend</em> - ce soir</td></tr><tr><td>die Nacht</td><td>la nuit</td><td><em>heute Nacht</em> - cette nuit</td></tr></tbody></table><h2 id="semaine-mois-annee" tabindex="-1">Semaine, mois, annee <a class="header-anchor" href="#semaine-mois-annee" aria-label="Permalink to “Semaine, mois, annee”">​</a></h2><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600">Passe</th><th class="p-3 text-center font-semibold text-green-700">Neutre</th><th class="p-3 text-right font-semibold text-gray-600">Futur</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 text-gray-600">letzte Woche</td><td class="p-3 text-center font-bold text-green-700">diese Woche</td><td class="p-3 text-right text-gray-600">nachste Woche</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 text-gray-600">letzten Monat</td><td class="p-3 text-center font-bold text-green-700">diesen Monat</td><td class="p-3 text-right text-gray-600">nachsten Monat</td></tr><tr class="border-t border-gray-100"><td class="p-3 text-gray-600">letztes Jahr</td><td class="p-3 text-center font-bold text-green-700">dieses Jahr</td><td class="p-3 text-right text-gray-600">nachstes Jahr</td></tr></tbody></table></div><h2 id="prepositions-de-temps-essentielles" tabindex="-1">Prepositions de temps essentielles <a class="header-anchor" href="#prepositions-de-temps-essentielles" aria-label="Permalink to “Prepositions de temps essentielles”">​</a></h2><div class="mt-4 grid gap-3"><div class="p-4 rounded-lg border border-gray-200"><div class="flex items-baseline gap-3"><div class="font-bold text-green-700 w-16 shrink-0">vor</div><div><div class="text-gray-800">il y a / avant</div><div class="text-sm text-gray-500 italic">vor einer Stunde - il y a une heure / vor dem Essen - avant le repas</div></div></div></div><div class="p-4 rounded-lg border border-gray-200"><div class="flex items-baseline gap-3"><div class="font-bold text-green-700 w-16 shrink-0">seit</div><div><div class="text-gray-800">depuis (action encore en cours)</div><div class="text-sm text-gray-500 italic">seit drei Jahren - depuis trois ans / seit Montag - depuis lundi</div></div></div></div><div class="p-4 rounded-lg border border-gray-200"><div class="flex items-baseline gap-3"><div class="font-bold text-green-700 w-16 shrink-0">nach</div><div><div class="text-gray-800">après</div><div class="text-sm text-gray-500 italic">nach dem Essen - après le repas / nach der Arbeit - après le travail</div></div></div></div><div class="p-4 rounded-lg border border-gray-200"><div class="flex items-baseline gap-3"><div class="font-bold text-green-700 w-16 shrink-0">in</div><div><div class="text-gray-800">dans (futur) / en (duree)</div><div class="text-sm text-gray-500 italic">in einer Stunde - dans une heure / in zwei Tagen - dans deux jours</div></div></div></div><div class="p-4 rounded-lg border border-gray-200"><div class="flex items-baseline gap-3"><div class="font-bold text-green-700 w-16 shrink-0">um</div><div><div class="text-gray-800">a (heure précise)</div><div class="text-sm text-gray-500 italic">um 8 Uhr - a 8h / um Mitternacht - a minuit</div></div></div></div><div class="p-4 rounded-lg border border-gray-200"><div class="flex items-baseline gap-3"><div class="font-bold text-green-700 w-16 shrink-0">am</div><div><div class="text-gray-800">le (jour de la semaine ou partie du jour)</div><div class="text-sm text-gray-500 italic">am Montag - le lundi / am Abend - le soir</div></div></div></div></div><div class="warning custom-block"><p class="custom-block-title">seit + présent en allemand = depuis + présent en français</p><p><em>Ich lerne seit drei Jahren Deutsch.</em> - J&#39;apprends l&#39;allemand depuis trois ans. En allemand, l&#39;action toujours en cours au moment où l&#39;on parlé se met au <strong>présent</strong>, pas au Perfekt. Contrairement au français qui utilisé aussi le présent, l&#39;allemand est ici cohérent avec lui - mais c&#39;est un piège si on traduit mot à mot depuis l&#39;anglais (<em>I have been learning</em> → Perfekt en anglais mais présent en allemand).</p></div>',14)])])}const v=t(i,[["render",r]]);export{p as __pageData,v as default};
